from flask import Flask, request, jsonify
from flask_cors import CORS
import logging
import time

app = Flask(__name__)
CORS(app)

users = {
    'alice': 'password1',
    'bob': 'password2'
}

LOG_FILE = 'application.log'

@app.route('/login', methods=['POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        email = request.form.get('email')

        if username not in users or users[username] != password:
            log_entry = f"{time.strftime('%Y-%m-%d %H:%M:%S')} - {request.remote_addr} - {request.user_agent.browser} - Failed login attempt by {username}\n"
            with open(LOG_FILE, 'a') as f:
                f.write(log_entry)
            return jsonify({'status': 'error', 'message': 'Invalid username or password'})
        else:
            log_entry = f"{time.strftime('%Y-%m-%d %H:%M:%S')} - {request.remote_addr} - {request.user_agent.browser} - Successful login by {username}\n"
            with open(LOG_FILE, 'a') as f:
                f.write(log_entry)
            return jsonify({'status': 'success', 'message': 'Login successful'})

if __name__ == "__main__":
    app.run()